<?php
require __DIR__.'/config.php'; require_admin(); $message='';$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){
 verify_csrf();$action=$_POST['action']??'';
 if($action==='settings'){foreach(['hotel_name','retention_days','contact_email'] as $key){$s=db()->prepare('REPLACE INTO settings (setting_key,setting_value) VALUES (?,?)');$s->execute([$key,trim($_POST[$key]??'')]);}$message='Ayarlar kaydedildi.';}
 $tables=['location'=>['location_definitions','Yer'],'department'=>['department_definitions','Departman'],'storage'=>['storage_definitions','Depo']];
 foreach($tables as $prefix=>[$table,$label]){
  if($action===$prefix.'_add'){$name=trim($_POST[$prefix.'_name']??'');if($name==='')$error="$label adı boş bırakılamaz.";else try{$order=(int)db()->query("SELECT COALESCE(MAX(sort_order),0)+1 FROM $table")->fetchColumn();$s=db()->prepare("INSERT INTO $table (name,sort_order) VALUES (?,?)");$s->execute([$name,$order]);$message="$label tanımı eklendi.";}catch(PDOException $e){$error="Bu $label zaten tanımlı.";}}
  if($action===$prefix.'_delete'){$s=db()->prepare("DELETE FROM $table WHERE id=?");$s->execute([(int)($_POST[$prefix.'_id']??0)]);$message="$label tanımı silindi.";}
  if($action===$prefix.'_edit'){$id=(int)($_POST[$prefix.'_id']??0);$name=trim($_POST[$prefix.'_name']??'');if(!$id||$name==='')$error="$label adı boş bırakılamaz.";else try{$s=db()->prepare("UPDATE $table SET name=? WHERE id=?");$s->execute([$name,$id]);$message="$label tanımı güncellendi.";}catch(PDOException $e){$error="Bu $label zaten tanımlı.";}}
 }
 if($action==='item_definition_add'){$category=trim($_POST['item_category']??'');$name=trim($_POST['item_name']??'');if(!$category||!$name)$error='Kategori ve eşya adı zorunludur.';else try{$order=(int)db()->query('SELECT COALESCE(MAX(sort_order),0)+1 FROM item_definitions')->fetchColumn();$s=db()->prepare('INSERT INTO item_definitions (category,name,sort_order) VALUES (?,?,?)');$s->execute([$category,$name,$order]);$message='Eşya tanımı eklendi.';}catch(PDOException $e){$error='Bu eşya zaten tanımlı.';}}
 if($action==='item_definition_delete'){$s=db()->prepare('DELETE FROM item_definitions WHERE id=?');$s->execute([(int)($_POST['item_definition_id']??0)]);$message='Eşya tanımı silindi.';}
 if($action==='item_definition_edit'){$id=(int)($_POST['item_definition_id']??0);$category=trim($_POST['item_category']??'');$name=trim($_POST['item_name']??'');if(!$id||!$category||!$name)$error='Kategori ve eşya adı zorunludur.';else try{$s=db()->prepare('UPDATE item_definitions SET category=?,name=? WHERE id=?');$s->execute([$category,$name,$id]);$message='Eşya tanımı güncellendi.';}catch(PDOException $e){$error='Bu eşya zaten tanımlı.';}}
 if($action==='user'){$name=trim($_POST['name']??'');$email=trim(strtolower($_POST['email']??''));$password=$_POST['password']??'';$role=in_array($_POST['role']??'', ['Admin','User'],true)?$_POST['role']:'User';if(!$name||!filter_var($email,FILTER_VALIDATE_EMAIL)||strlen($password)<6)$error='Kullanıcı bilgilerini kontrol edin.';else{$check=db()->prepare('SELECT id FROM users WHERE LOWER(email)=LOWER(?) LIMIT 1');$check->execute([$email]);if($check->fetch())$error='Bu e-posta adresi zaten kullanılıyor. Aynı e-posta ile ikinci kullanıcı oluşturulamaz.';else try{$s=db()->prepare('INSERT INTO users (name,email,password_hash,role,active) VALUES (?,?,?,?,1)');$s->execute([$name,$email,password_hash($password,PASSWORD_DEFAULT),$role]);$message='Kullanıcı oluşturuldu.';}catch(PDOException $e){$error='Bu e-posta adresi zaten kullanılıyor. Aynı e-posta ile ikinci kullanıcı oluşturulamaz.';}}}
}
$settings=[];foreach(db()->query('SELECT setting_key,setting_value FROM settings') as $r)$settings[$r['setting_key']]=$r['setting_value'];
$locations=db()->query('SELECT id,name FROM location_definitions WHERE active=1 ORDER BY sort_order,name')->fetchAll();$departments=db()->query('SELECT id,name FROM department_definitions WHERE active=1 ORDER BY sort_order,name')->fetchAll();$storages=db()->query('SELECT id,name FROM storage_definitions WHERE active=1 ORDER BY sort_order,name')->fetchAll();$itemDefinitions=db()->query('SELECT id,category,name FROM item_definitions WHERE active=1 ORDER BY sort_order,category,name')->fetchAll();$users=db()->query('SELECT id,name,email,role,active FROM users ORDER BY id')->fetchAll();
function definition_list(array $rows,string $prefix,string $confirm):void{foreach($rows as $row){?><div><span><?=e($row['name'])?></span><div class="row-actions"><form method="post" onsubmit="return editDefinition(this,'<?=e($row['name'])?>')"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="<?=$prefix?>_edit"><input type="hidden" name="<?=$prefix?>_id" value="<?=(int)$row['id']?>"><input type="hidden" name="<?=$prefix?>_name"><button class="edit-button">Düzenle</button></form><form method="post" onsubmit="return confirm('<?=e($confirm)?>')"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="<?=$prefix?>_delete"><input type="hidden" name="<?=$prefix?>_id" value="<?=(int)$row['id']?>"><button class="delete-button">Sil</button></form></div></div><?php }}
?>
