<section id="esyalar" class="title-row admin-subtitle"><div><h1>Eşya tanımları</h1><p>Kategori ve eşya seçeneklerini yönetin.</p></div></section><form class="panel item-definition-add" method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="item_definition_add"><input name="item_category" placeholder="Kategori" required><input name="item_name" placeholder="Eşya adı" required><button class="primary">Eşya ekle</button></form><section class="panel location-list"><?php foreach($itemDefinitions as $d):?><div><span><b><?=e($d['category'])?></b> – <?=e($d['name'])?></span><div class="row-actions"><form method="post" onsubmit="return editItem(this,'<?=e($d['category'])?>','<?=e($d['name'])?>')"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="item_definition_edit"><input type="hidden" name="item_definition_id" value="<?=(int)$d['id']?>"><input type="hidden" name="item_category"><input type="hidden" name="item_name"><button class="edit-button">Düzenle</button></form><form method="post" onsubmit="return confirm('Bu eşya tanımı silinsin mi?')"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="item_definition_delete"><input type="hidden" name="item_definition_id" value="<?=(int)$d['id']?>"><button class="delete-button">Sil</button></form></div></div><?php endforeach?></section>
<section id="kullanicilar" class="title-row admin-subtitle"><div><h1>Kullanıcılar</h1><p>Admin ayarları yönetir; User uygulamayı kullanır.</p></div></section><form class="panel form-grid" method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="user"><label>Ad soyad<input name="name" required></label><label>E-posta<input type="email" name="email" required></label><label>Şifre<input type="password" name="password" minlength="6" required></label><label>Rol<select name="role"><option>User</option><option>Admin</option></select></label><div class="wide actions"><button class="primary">Kullanıcı ekle</button></div></form><section class="panel users-panel"><table><thead><tr><th>Ad soyad</th><th>E-posta</th><th>Rol</th><th>Durum</th><th>İşlemler</th></tr></thead><tbody><?php foreach($users as $u):?><tr><td><?=e($u['name'])?></td><td><?=e($u['email'])?></td><td><span class="role-badge"><?=e($u['role'])?></span></td><td><?=$u['active']?'Aktif':'Pasif'?></td><td><?php if($u['role']==='User'):?><a class="edit-button user-edit-link" href="<?=url('user-edit.php?id='.(int)$u['id'])?>">Düzenle / Şifre</a><?php else:?><span class="admin-protected">Yönetici</span><?php endif?></td></tr><?php endforeach?></tbody></table></section>
</main><script>function editDefinition(form,current){const value=prompt('Yeni adı girin:',current);if(value===null||!value.trim())return false;form.querySelector('input[name$="_name"]').value=value.trim();return true}function editItem(form,category,name){const newCategory=prompt('Kategori:',category);if(newCategory===null)return false;const newName=prompt('Eşya adı:',name);if(newName===null||!newCategory.trim()||!newName.trim())return false;form.item_category.value=newCategory.trim();form.item_name.value=newName.trim();return true}</script></body></html>
